import java.util.Base64;import scala.collection.mutable
object Brush{case class Point(x:Double,y:Double);case class DrawingPath(points:Vector[Point],d:String,fontSize:Double);case class Segment(a:Point,b:Point,start:Double,length:Double);case class ArcPath(points:Vector[Point],segments:Vector[Segment],totalLength:Double);case class PathSample(x:Double,y:Double,angle:Double,progress:Double);case class Options(fontSize:Double=40,fontFamily:String="Arial, sans-serif",fontWeight:String="700",letterSpacing:Option[Double]=None,color:String="#ffffff",magicGradient:Boolean=false,opacity:Double=1,strokeColor:String="rgba(15,23,42,0.72)",strokeWidth:Double=1.5,shadow:Boolean=true,repeatText:Boolean=true,revealProgress:Double=1)
 private def finite(p:Point)=p.x.isFinite&&p.y.isFinite;private def clamp(v:Double,a:Double,b:Double)=if(v.isFinite)v.max(a).min(b)else a;private def dist(a:Point,b:Point)=math.sqrt((b.x-a.x)*(b.x-a.x)+(b.y-a.y)*(b.y-a.y));private def fmt(v:Double)={val n=math.round(v*100)/100.0;if(n==0)"0"else f"$n%.2f".replaceFirst("\\.?0+$","")};private def fp(p:Point)=s"${fmt(p.x)} ${fmt(p.y)}";private def along(a:Point,b:Point,d:Double)={val l=dist(a,b);if(l==0)a else {val t=(d/l).min(1);Point(a.x+(b.x-a.x)*t,a.y+(b.y-a.y)*t)}};private def turn(a:Point,b:Point,c:Point)={val ux=b.x-a.x;val uy=b.y-a.y;val vx=c.x-b.x;val vy=c.y-b.y;val ul=math.sqrt(ux*ux+uy*uy);val vl=math.sqrt(vx*vx+vy*vy);if(ul==0||vl==0)0 else math.acos(clamp((ux*vx+uy*vy)/(ul*vl),-1,1))*180/math.Pi}
 def buildRoundedDrawingPath(input:Seq[Point],fs:Double=40)={val p=input.filter(finite).toVector;if(p.isEmpty)""else if(p.size==1)s"M ${fp(p.head)}"else {val radius=12d.max(fs*1.25);val middle=(1 until p.size-1).map{i=>val d=radius.min(dist(p(i-1),p(i))*0.45).min(dist(p(i),p(i+1))*0.45);s"L ${fp(along(p(i),p(i-1),d))} Q ${fp(p(i))} ${fp(along(p(i),p(i+1),d))}"};(Vector("M "+fp(p.head))++middle++Vector("L "+fp(p.last))).mkString(" ")}}
 def createDrawingPath(p:Point,fs:Double=40)=if(finite(p))DrawingPath(Vector(p),"M "+fp(p),fs)else DrawingPath(Vector(),"",fs);def appendDrawingPoint(path:DrawingPath,p:Point)={if(!finite(p)||path.points.isEmpty||dist(path.points.last,p)<3)path else {val n=if(path.points.size==1||turn(path.points(path.points.size-2),path.points.last,p)>=18)path.points:+p else path.points.updated(path.points.size-1,p);DrawingPath(n,buildRoundedDrawingPath(n,path.fontSize),path.fontSize)}};private def drawing(points:Seq[Point],fs:Double)=points.filter(finite).foldLeft(Option.empty[DrawingPath]){(path,p)=>Some(path.map(appendDrawingPoint(_,p)).getOrElse(createDrawingPath(p,fs)))}.filter(_.points.size>=2)
 private def perp(p:Point,a:Point,b:Point)={val dx=b.x-a.x;val dy=b.y-a.y;val l=dx*dx+dy*dy;if(l==0)dist(p,a)else {val t=clamp(((p.x-a.x)*dx+(p.y-a.y)*dy)/l,0,1);dist(p,Point(a.x+t*dx,a.y+t*dy))}};private def simplify(p:Vector[Point],tol:Double)={if(p.size<=2)p else {val keep=Array.fill(p.size)(false);keep(0)=true;keep(p.size-1)=true;val stack=mutable.Stack((0,p.size-1));while(stack.nonEmpty){val(first,last)=stack.pop();var best=0d;var index = -1;for(i<-first+1 until last){val d=perp(p(i),p(first),p(last));if(d>best){best=d;index=i}};if(best>tol){keep(index)=true;stack.push((first,index));stack.push((index,last))}};p.zipWithIndex.collect{case(v,i)if keep(i)=>v}}}
 def prepareArcLengthPath(input:Seq[Point],minimum:Double=0.5)={val valid=input.filter(finite).toVector;val filtered=valid.foldLeft(Vector.empty[Point]){(a,p)=>if(a.isEmpty||dist(a.last,p)>=minimum)a:+p else a};val f=if(valid.nonEmpty&&filtered.nonEmpty&&dist(filtered.last,valid.last)>0)filtered:+valid.last else filtered;val points=simplify(f,(minimum*0.5).max(0.1));var total=0d;val segments=points.sliding(2).flatMap{case Vector(a,b)=>val l=dist(a,b);if(l>0){val s=Segment(a,b,total,l);total+=l;Some(s)}else None;case _=>None}.toVector;ArcPath(points,segments,total)};private def pointAt(p:ArcPath,d0:Double)={if(p.segments.isEmpty)Point(0,0)else {val d=clamp(d0,0,p.totalLength);p.segments.find(s=>d<=s.start+s.length).map{s=>val t=clamp((d-s.start)/s.length,0,1);Point(s.a.x+(s.b.x-s.a.x)*t,s.a.y+(s.b.y-s.a.y)*t)}.getOrElse(p.segments.last.b)}};def sampleAt(p:ArcPath,progress0:Double,fs:Double=40)={val progress=clamp(progress0,0,1);if(p.totalLength<=0)PathSample(0,0,0,progress)else {val d=p.totalLength*progress;val w=(fs*1.1).max(0.75).min(p.totalLength*0.06).max(0.75);val a=pointAt(p,d-w);val b=pointAt(p,d+w);val v=pointAt(p,d);PathSample(v.x,v.y,math.atan2(b.y-a.y,b.x-a.x),progress)}}
 def stableRepeatedText(text:String,fs:Double)={val p=text.trim;if(p.isEmpty)""else {val count=math.ceil(20000/fs.max(p.codePointCount(0,p.length)*fs*0.62)).toInt.max(16).min(256);Vector.fill(count)(p).mkString("   ")}};private def esc(v:Any)=v.toString.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;").replace("\"","&quot;").replace("'","&apos;")
 def renderSvg(bytes:Array[Byte],mime:String,width:Double,height:Double,points:Seq[Point],text:String,o:Options=Options())={require(Set("image/png","image/jpeg","image/webp","image/gif","image/avif")(mime));val phrase=text.trim;val fs=if(o.fontSize.isFinite&&o.fontSize>0)o.fontSize else 40d;val path=drawing(points,fs).getOrElse(throw new IllegalArgumentException("two points required"));require(phrase.nonEmpty);val repeated=if(o.repeatText)stableRepeatedText(phrase,fs)else phrase;val gradient=if(o.magicGradient)"<linearGradient id=\"brush-gradient\" x1=\"100\" y1=\"150\" x2=\"900\" y2=\"850\" gradientUnits=\"userSpaceOnUse\"><stop offset=\"0%\" stop-color=\"#ec4899\"/><stop offset=\"20%\" stop-color=\"#f97316\"/><stop offset=\"40%\" stop-color=\"#facc15\"/><stop offset=\"60%\" stop-color=\"#10b981\"/><stop offset=\"80%\" stop-color=\"#3b82f6\"/><stop offset=\"100%\" stop-color=\"#8b5cf6\"/></linearGradient>"else "";val shadow=if(o.shadow)"<filter id=\"brush-shadow\"><feDropShadow dx=\"0\" dy=\"2\" stdDeviation=\"2\" flood-color=\"#0f172a\" flood-opacity=\"0.65\"/></filter>"else "";val filter=if(o.shadow)" filter=\"url(#brush-shadow)\""else "";val fill=if(o.magicGradient)"url(#brush-gradient)"else esc(o.color);val spacing=o.letterSpacing.getOrElse((fs*0.06).max(0.75));val reveal=clamp(o.revealProgress,0,1);val d=esc(path.d);s"""<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="${fmt(width)}" height="${fmt(height)}" viewBox="0 0 ${fmt(width)} ${fmt(height)}"><image width="${fmt(width)}" height="${fmt(height)}" preserveAspectRatio="xMidYMid slice" href="data:$mime;base64,${Base64.getEncoder.encodeToString(bytes)}"/><defs><path id="brush-path" d="$d"/>$gradient$shadow<mask id="brush-reveal"><rect width="100%" height="100%" fill="black"/><path d="$d" pathLength="1" fill="none" stroke="white" stroke-width="${fmt(fs*2.4)}" stroke-linecap="round" stroke-linejoin="round" stroke-dasharray="1" stroke-dashoffset="${fmt(1-reveal)}"/></mask></defs><g mask="url(#brush-reveal)" opacity="${fmt(clamp(o.opacity,0,1))}"$filter><text font-family="${esc(o.fontFamily)}" font-size="${fmt(fs)}" font-weight="${esc(o.fontWeight)}" letter-spacing="${fmt(spacing)}" fill="$fill" stroke="${esc(o.strokeColor)}" stroke-width="${fmt(o.strokeWidth.max(0))}" paint-order="stroke fill"><textPath href="#brush-path" xlink:href="#brush-path" startOffset="0" spacing="exact">${esc(repeated)}</textPath></text></g></svg>
"""}
}
